export default{async fetch(request,env={},ctx={}){env={...(env||{}),__REQUEST_ORIGIN:request.headers.get("Origin")||""};try{const url=new URL(request.url);const path=normalizePath(url.pathname);if(request.method==="OPTIONS")return corsResponse("",204,env);if(path==="/"&&request.method==="GET")return handleRoot(env);if(path==="/health"&&request.method==="GET")return handleHealth(env);if(path==="/debug"&&request.method==="GET")return handleDebug(env);if(path==="/config"&&request.method==="GET")return handleConfig(env);if(path==="/auth-test/open"&&request.method==="GET")return safeGuestyRoute(env,()=>handleOpenAuthTest(env));if(path==="/auth-test/booking"&&request.method==="GET")return safeGuestyRoute(env,()=>handleBookingAuthTest(env));if((path==="/payment-provider"||path==="/api/payment-provider")&&request.method==="GET")return cachedRoute(request,env,ctx,{cacheName:"payment-provider",ttlSeconds:PAYMENT_PROVIDER_TTL_SECONDS,handler:()=>safeGuestyRoute(env,()=>handlePaymentProvider(url,env))});if((path==="/api/discover-listings"||path==="/discover-listings")&&request.method==="GET")return cachedRoute(request,env,ctx,{cacheName:"discover-listings",ttlSeconds:LISTINGS_TTL_SECONDS,handler:()=>safeGuestyRoute(env,()=>handleDiscoverListings(url,env))});if((path==="/api/listings"||path==="/listings")&&request.method==="GET")return cachedRoute(request,env,ctx,{cacheName:"listings",ttlSeconds:LISTINGS_TTL_SECONDS,handler:()=>safeGuestyRoute(env,()=>handleListings(url,env))});if((path==="/api/listing"||path==="/listing")&&request.method==="GET")return cachedRoute(request,env,ctx,{cacheName:"listing",ttlSeconds:LISTINGS_TTL_SECONDS,handler:()=>safeGuestyRoute(env,()=>handleListing(url,env))});if((path==="/api/images"||path==="/images")&&request.method==="GET")return cachedRoute(request,env,ctx,{cacheName:"images",ttlSeconds:IMAGES_TTL_SECONDS,handler:()=>safeGuestyRoute(env,()=>handleImages(url,env))});if((path==="/api/calendar"||path==="/calendar"||path==="/api/availability"||path==="/availability")&&request.method==="GET")return staleCachedRoute(request,env,ctx,{cacheName:"calendar",freshSeconds:CALENDAR_FRESH_SECONDS,staleSeconds:CALENDAR_STALE_SECONDS,handler:()=>safeGuestyRoute(env,()=>handleCalendar(url,env))});if((path==="/api/calendar-raw"||path==="/calendar-raw")&&request.method==="GET")return liveRoute(env,()=>safeGuestyRoute(env,()=>handleCalendarRaw(url,env)));if((path==="/api/quote"||path==="/quote")&&request.method==="POST")return quoteDedupeRoute(request,env);if((path==="/api/book"||path==="/book")&&request.method==="POST")return liveRoute(env,()=>safeGuestyRoute(env,()=>handleBook(request,env)));if((path==="/api/booking-status"||path==="/booking-status")&&request.method==="GET")return liveRoute(env,()=>safeGuestyRoute(env,()=>handleBookingStatus(url,env)));return json({ok:false,error:"Not found",path,routes:publicRoutes()},404,env)}catch(err){return errorResponse(err,env)}}};

function publicRoutes(){return["GET /health","GET /debug","GET /config","GET /auth-test/open","GET /auth-test/booking","GET /payment-provider?listingId=...","GET /api/payment-provider?listingId=...","GET /api/listings","GET /api/discover-listings","GET /api/listing?listingId=...","GET /api/images?listingId=...","GET /api/calendar?listingId=...&from=2026-07-01&to=2026-07-31","GET /api/availability?listingId=...&from=2026-07-01&to=2026-07-31","POST /api/quote","POST /api/book","GET /api/booking-status?reservationId=..."]}
function handleRoot(env){return json({ok:true,service:"timbercrest-guesty-worker",buildVersion:BUILD_VERSION,property:"Timbercrest Mansions",routes:publicRoutes()},200,env)}
function handleHealth(env){return json({ok:true,service:"timbercrest-guesty-worker",buildVersion:BUILD_VERSION,time:new Date().toISOString()},200,env)}
function handleDebug(env){const configuredListings=getListingConfigs(env);return json({ok:true,buildVersion:BUILD_VERSION,cacheVersion:CACHE_VERSION,tokenCacheVersion:TOKEN_CACHE_VERSION,quoteCacheVersion:QUOTE_CACHE_VERSION,cacheBackend:hasKV(env)?"KV":"NO KV BINDING - live fallback",variables:{ALLOWED_ORIGINS:Boolean(env.ALLOWED_ORIGINS),CURRENCY:Boolean(env.CURRENCY),SITE_BASE_URL:Boolean(env.SITE_BASE_URL),TIMEZONE:Boolean(env.TIMEZONE),GUESTY_LISTING_IDS:Boolean(env.GUESTY_LISTING_IDS),TIMBERCREST_LISTINGS_JSON:Boolean(env.TIMBERCREST_LISTINGS_JSON),TIMBERCREST_LISTINGS_JSON_type:typeof env.TIMBERCREST_LISTINGS_JSON,GUESTY_OPEN_API_CLIENT_ID:Boolean(env.GUESTY_OPEN_API_CLIENT_ID),GUESTY_OPEN_API_CLIENT_SECRET:Boolean(env.GUESTY_OPEN_API_CLIENT_SECRET),GUESTY_CLIENT_ID_BOOKING:Boolean(env.GUESTY_CLIENT_ID),GUESTY_CLIENT_SECRET_BOOKING:Boolean(env.GUESTY_CLIENT_SECRET),GUESTY_PAYMENT_PROVIDER_ID_OPTIONAL:Boolean(env.GUESTY_PAYMENT_PROVIDER_ID),TM_CACHE_KV_BINDING:hasKV(env)},configuredListings,status:{baseConfigReady:Boolean(env.ALLOWED_ORIGINS&&env.CURRENCY&&env.SITE_BASE_URL&&env.TIMEZONE),listingsConfigured:configuredListings.length>0||Boolean(env.GUESTY_LISTING_IDS),openApiReady:Boolean(env.GUESTY_OPEN_API_CLIENT_ID&&env.GUESTY_OPEN_API_CLIENT_SECRET),bookingApiReady:Boolean(env.GUESTY_CLIENT_ID&&env.GUESTY_CLIENT_SECRET),paymentProviderReady:Boolean(env.GUESTY_PAYMENT_PROVIDER_ID)},routes:publicRoutes()},200,env)}
function handleConfig(env){return json({ok:true,propertyName:"Timbercrest Mansions",currency:env.CURRENCY||"USD",timezone:env.TIMEZONE||"America/New_York",siteBaseUrl:env.SITE_BASE_URL||"https://lschacht99.github.io/Timbercrest-Mansion",allowedOrigins:env.ALLOWED_ORIGINS||null,paymentProviderId:env.GUESTY_PAYMENT_PROVIDER_ID||null,paymentProviderNote:env.GUESTY_PAYMENT_PROVIDER_ID?"Using GUESTY_PAYMENT_PROVIDER_ID from Cloudflare.":"Use GET /payment-provider?listingId=... after adding Open API OAuth credentials.",listingCount:getListingConfigs(env).length,bookingPage:"/booking.html",guestyPayScript:"https://pay.guesty.com/tokenization/v1/init.js"},200,env)}
async function handleOpenAuthTest(env){const tokenData=await getOpenApiTokenData(env,true);return json({ok:true,auth:"open-api",tokenReceived:Boolean(tokenData.token),scope:tokenData.scope,expiresAt:new Date(tokenData.expiresAt).toISOString(),message:"Open API credentials work."},200,env)}
async function handleBookingAuthTest(env){const tokenData=await getBookingApiTokenData(env,true);return json({ok:true,auth:"booking-api",tokenReceived:Boolean(tokenData.token),scope:tokenData.scope,expiresAt:new Date(tokenData.expiresAt).toISOString(),message:"Booking Engine credentials work."},200,env)}
async function handlePaymentProvider(url,env){const forceApi=url.searchParams.get("force")==="1";const listingId=resolveListingIdFromRequest(url,env);assertRequired(listingId,"Missing listingId. Use ?listingId=GuestyId or ?id=the-birch.");if(env.GUESTY_PAYMENT_PROVIDER_ID&&!forceApi)return json({ok:true,listingId,paymentProviderId:env.GUESTY_PAYMENT_PROVIDER_ID,source:"GUESTY_PAYMENT_PROVIDER_ID Cloudflare variable",note:"Add ?force=1 to call Guesty Open API again."},200,env);const data=await getPaymentProviderByListing(env,listingId);const providerId=extractPaymentProviderId(data);if(!providerId)throw new PublicError("Could not find paymentProviderId in Guesty response",502,{body:data});return json({ok:true,listingId,paymentProviderId:providerId,source:"Guesty Open API provider-by-listing",paymentProvider:env.DEBUG_RAW==="1"?data:summarizePaymentProvider(data),instructions:["Copy paymentProviderId into Cloudflare as GUESTY_PAYMENT_PROVIDER_ID after verifying it.","This is not a ccToken. The ccToken is generated later by the GuestyPay browser tokenization widget."]},200,env)}
async function handleDiscoverListings(url,env){const all=await getAllGuestyListings(env);const query=normalizeMatchText(url.searchParams.get("q")||"");const filtered=query?all.filter(l=>listingSearchText(l).includes(query)):all;return json({ok:true,count:filtered.length,listings:filtered.map(l=>summarizeGuestyListing(l,env))},200,env)}
async function handleListings(url,env){const configs=getListingConfigs(env);const forceDiscover=url.searchParams.get("forceDiscover")==="1";const shouldDiscover=forceDiscover||configs.some(c=>!c.listingId);let allListings=null;if(shouldDiscover)allListings=await getAllGuestyListings(env);const listings=[];for(const config of configs){let listing=null;if(config.listingId&&!forceDiscover){try{listing=await getGuestyListingById(config.listingId,env)}catch(e){if(!allListings)allListings=await getAllGuestyListings(env)}}if(!listing&&allListings)listing=findBestListingMatch(allListings,config);listings.push(listing?normalizeListing(listing,env,config):fallbackListingFromConfig(config,env))}listings.sort((a,b)=>(a.sort||99)-(b.sort||99));return json({ok:true,source:getConfigSource(env),count:listings.length,currency:env.CURRENCY||"USD",timezone:env.TIMEZONE||"America/New_York",properties:listings,listings},200,env)}
async function handleListing(url,env){const listingId=resolveListingIdFromRequest(url,env);assertRequired(listingId,"Missing listingId");const config=findConfigByAnyId(listingId,env)||{listingId};const listing=await getGuestyListingById(listingId,env);return json({ok:true,listing:normalizeListing(listing,env,config),raw:env.DEBUG_RAW==="1"?listing:undefined},200,env)}
async function handleImages(url,env){const listingId=resolveListingIdFromRequest(url,env);assertRequired(listingId,"Missing listingId");const config=findConfigByAnyId(listingId,env)||{listingId};const listing=await getGuestyListingById(listingId,env);return json({ok:true,listingId,siteId:config.siteId||null,source:"Guesty listing",images:normalizeImagesFromListing(listing,config),raw:env.DEBUG_RAW==="1"?listing:undefined},200,env)}
async function handleCalendar(url,env){const calendar=await fetchCalendarFromGuesty(url,env);return buildCalendarResponse(calendar,url,env,"calendar")}
async function handleCalendarRaw(url,env){const calendar=await fetchCalendarFromGuesty(url,env);return json({ok:true,listingId:resolveListingIdFromRequest(url,env),from:url.searchParams.get("from")||url.searchParams.get("startDate"),to:url.searchParams.get("to")||url.searchParams.get("endDate"),rawShape:describeShape(calendar),raw:calendar},200,env)}
function buildCalendarResponse(calendar,url,env,routeName){const days=normalizeCalendar(calendar);return json({ok:true,route:routeName,listingId:resolveListingIdFromRequest(url,env),from:url.searchParams.get("from")||url.searchParams.get("startDate"),to:url.searchParams.get("to")||url.searchParams.get("endDate"),adults:toNumberOrNull(url.searchParams.get("adults")),children:toNumberOrNull(url.searchParams.get("children")),currency:env.CURRENCY||"USD",timezone:env.TIMEZONE||"America/New_York",days,daysCount:days.length,rawShape:describeShape(calendar),raw:env.DEBUG_RAW==="1"?calendar:undefined},200,env)}
async function fetchCalendarFromGuesty(url,env){const listingId=resolveListingIdFromRequest(url,env);const from=url.searchParams.get("from")||url.searchParams.get("startDate");const to=url.searchParams.get("to")||url.searchParams.get("endDate");assertRequired(listingId,"Missing listingId");assertDate(from,"Missing or invalid from date. Use YYYY-MM-DD.");assertDate(to,"Missing or invalid to date. Use YYYY-MM-DD.");const query=new URLSearchParams({startDate:from,endDate:to,includeAllotment:"true"});return guestyOpenApi(env,"/availability-pricing/api/calendar/listings/"+encodeURIComponent(listingId)+"?"+query.toString(),{method:"GET"})}
async function handleQuote(request,env){const body=await readJson(request);const payload=buildQuotePayloadFromBody(body,env);const quote=await guestyBookingApi(env,"/reservations/quotes",{method:"POST",body:JSON.stringify(payload)});return json({ok:true,quote:normalizeQuote(quote,env),raw:env.DEBUG_RAW==="1"?quote:undefined},200,env)}
async function handleBook(request,env){const body=await readJson(request);if(!body.quoteId&&!body.quote_id)return json({ok:true,mode:"inquiry",message:"Booking inquiry received by Worker. Add quoteId, ratePlanId and GuestyPay ccToken for instant Guesty booking.",received:{propertyIds:body.propertyIds||[],listingIds:body.listingIds||[],checkIn:body.checkIn||null,checkOut:body.checkOut||null,guests:body.guests||null,email:body.email||null,firstName:body.firstName||null,lastName:body.lastName||null,phone:body.phone||null,isEvent:Boolean(body.isEvent),eventType:body.eventType||null,message:body.message||null,totalQuoted:body.totalQuoted||null}},200,env);const quoteId=body.quoteId||body.quote_id;const ratePlanId=body.ratePlanId||body.rateplan_id||body.ratePlanID;const ccToken=body.ccToken||body.guestypayToken||body.guestypay_token;const guest=body.guest||buildGuestFromFlatBody(body);assertRequired(quoteId,"Missing quoteId");assertRequired(ratePlanId,"Missing ratePlanId");assertRequired(ccToken,"Missing GuestyPay token / ccToken");validateGuest(guest);if(!body.acceptAgreement&&!body.acceptRentalAgreement&&!body.accept_agreement)throw new PublicError("Rental agreement must be accepted",400);const payload={ratePlanId,ccToken,guest,policy:body.policy||buildPolicyFromBody(body)};if(body.paymentProviderId||body.payment_provider_id||env.GUESTY_PAYMENT_PROVIDER_ID)payload.paymentProviderId=body.paymentProviderId||body.payment_provider_id||env.GUESTY_PAYMENT_PROVIDER_ID;const reservation=await guestyBookingApi(env,"/reservations/quotes/"+encodeURIComponent(quoteId)+"/instant",{method:"POST",body:JSON.stringify(payload)});return json({ok:true,message:"Reservation created",reservation:normalizeReservation(reservation),raw:env.DEBUG_RAW==="1"?reservation:undefined},200,env)}
async function handleBookingStatus(url,env){const reservationId=url.searchParams.get("reservationId")||url.searchParams.get("id");assertRequired(reservationId,"Missing reservationId");const reservation=await guestyOpenApi(env,"/reservations-v3/"+encodeURIComponent(reservationId),{method:"GET"});return json({ok:true,reservation:normalizeReservation(reservation),raw:env.DEBUG_RAW==="1"?reservation:undefined},200,env)}

function getListingConfigs(env){const rawJson=env.TIMBERCREST_LISTINGS_JSON??env.TIMBERCREST_LISTINGS??env.LISTINGS_JSON;const parsed=parseFlexibleJson(rawJson,null);const fromJson=normalizeConfigCollection(parsed);if(fromJson.length)return fromJson.map((item,index)=>normalizeConfig(item,index));const ids=parseCSV(env.GUESTY_LISTING_IDS);if(ids.length)return ids.map((listingId,index)=>normalizeConfig({...DEFAULT_CONFIGS[index],listingId},index));return DEFAULT_CONFIGS.map((item,index)=>normalizeConfig(item,index))}
function normalizeConfigCollection(value){if(!value)return[];if(Array.isArray(value))return value;if(Array.isArray(value.listings))return value.listings;if(Array.isArray(value.properties))return value.properties;if(Array.isArray(value.data))return value.data;if(typeof value==="object")return Object.entries(value).map(([key,item])=>typeof item==="string"?{siteId:key,listingId:item}:item&&typeof item==="object"?{siteId:item.siteId||key,...item}:null).filter(Boolean);return[]}
function normalizeConfig(item,index){const siteId=item.siteId||item.propertyId||DEFAULT_CONFIGS[index]?.siteId||slugify(item.publicName||item.name||item.guestyName||"property");const defaults=DEFAULT_CONFIGS.find(c=>c.siteId===siteId)||DEFAULT_CONFIGS[index]||{};const match=unique([...(Array.isArray(defaults.match)?defaults.match:[]),...(Array.isArray(defaults.titles)?defaults.titles:[]),defaults.publicName,defaults.guestyName,...(Array.isArray(item.match)?item.match:[]),...(Array.isArray(item.titles)?item.titles:[]),item.title,item.name,item.nickname,item.guestyName,item.publicName].filter(Boolean));return{...defaults,...item,siteId,publicName:item.publicName||defaults.publicName||item.name||item.guestyName||siteId,guestyName:item.guestyName||defaults.guestyName||item.name||"",listingId:item.listingId||item.guestyListingId||item._id||item.id||defaults.listingId||"",match,href:item.href||defaults.href||"booking.html?ids="+encodeURIComponent(siteId),sort:Number(item.sort||defaults.sort||index+1),g1:item.g1||defaults.g1||"#3a3f49",g2:item.g2||defaults.g2||"#16181d"}}
function getConfigSource(env){if(env.TIMBERCREST_LISTINGS_JSON!==undefined)return"TIMBERCREST_LISTINGS_JSON";if(env.GUESTY_LISTING_IDS)return"GUESTY_LISTING_IDS";return"DEFAULT_CONFIGS"}
function findConfigByAnyId(value,env){const v=String(value||"");if(!v)return null;const n=normalizeMatchText(v);return getListingConfigs(env).find(c=>String(c.siteId)===v||String(c.listingId)===v||normalizeMatchText(c.siteId)===n||normalizeMatchText(c.publicName)===n||normalizeMatchText(c.guestyName)===n||(Array.isArray(c.match)&&c.match.some(m=>normalizeMatchText(m)===n)))||null}
function resolveListingIdFromRequest(url,env){const direct=url.searchParams.get("listingId")||url.searchParams.get("guestyListingId");if(direct)return direct;const siteId=url.searchParams.get("id")||url.searchParams.get("propertyId")||url.searchParams.get("siteId")||url.searchParams.get("title");const config=findConfigByAnyId(siteId,env);if(config?.listingId)return config.listingId;const first=getListingConfigs(env).find(item=>item.listingId);return first?.listingId||""}
function resolveListingIdFromBody(body,env){const direct=body.listingId||body.guestyListingId||body.listingIds?.[0]||body.propertyListingId;if(direct)return direct;const key=body.id||body.propertyId||body.propertyIds?.[0]||body.siteId||body.title||body.name;const config=findConfigByAnyId(key,env);if(config?.listingId)return config.listingId;const first=getListingConfigs(env).find(item=>item.listingId);return first?.listingId||""}

async function getGuestyListingById(listingId,env){assertRequired(listingId,"Missing listingId");return guestyOpenApi(env,"/listings/"+encodeURIComponent(listingId),{method:"GET"})}
async function getAllGuestyListings(env){const query=new URLSearchParams({limit:"100",fields:"_id id title nickname name publicName internalName address accommodates maxGuests bedrooms bedroomsCount bathrooms bathroomsCount pictures picture prices rates terms active listed"});const data=await guestyOpenApi(env,"/listings?"+query.toString(),{method:"GET"});return extractArray(data)}
async function getPaymentProviderByListing(env,listingId){assertRequired(listingId,"Missing listingId");const params=new URLSearchParams({listingId,includeInactiveProviders:"true",fields:"_id id name nickname key type processor status active paymentMethods supportedMethods providerId paymentProviderId"});const paths=["/payment-providers/provider-by-listing?"+params.toString(),"/payment-provider/provider-by-listing?"+params.toString(),"/payment-providers?"+params.toString()];let lastError=null;for(const apiPath of paths){try{return await guestyOpenApi(env,apiPath,{method:"GET"})}catch(err){lastError=err}}throw lastError||new PublicError("Could not fetch payment provider",502)}
async function guestyOpenApi(env,path,options={}){const token=await getOpenApiToken(env);const res=await fetch(OPEN_API_BASE+path,{method:options.method||"GET",headers:{accept:"application/json","content-type":"application/json",authorization:"Bearer "+token,...(options.headers||{})},body:options.body});return parseGuestyResponse(res,"Guesty Open API")}
async function guestyBookingApi(env,path,options={}){const token=await getBookingApiToken(env);const res=await fetch(BOOKING_API_BASE+path,{method:options.method||"GET",headers:{accept:"application/json","content-type":"application/json",authorization:"Bearer "+token,...(options.headers||{})},body:options.body});return parseGuestyResponse(res,"Guesty Booking API")}
async function getOpenApiToken(){return (await getOpenApiTokenData(arguments[0],false)).token}
async function getOpenApiTokenData(env,forceRefresh=false){if(!forceRefresh&&openTokenCache&&tokenStillValid(openTokenCache))return openTokenCache;if(!forceRefresh){const kvToken=await getTokenFromKV(env,"open-api");if(kvToken){openTokenCache=kvToken;return kvToken}}const tokenData=await requestToken({tokenUrl:OPEN_API_TOKEN_URL,clientId:env.GUESTY_OPEN_API_CLIENT_ID,clientSecret:env.GUESTY_OPEN_API_CLIENT_SECRET,scope:"open-api",label:"Guesty Open API",missingMessage:"Missing Open API credentials. Add GUESTY_OPEN_API_CLIENT_ID and GUESTY_OPEN_API_CLIENT_SECRET."});openTokenCache=tokenData;await putTokenToKV(env,"open-api",tokenData);return tokenData}
async function getBookingApiToken(env){return (await getBookingApiTokenData(env,false)).token}
async function getBookingApiTokenData(env,forceRefresh=false){if(!forceRefresh&&bookingTokenCache&&tokenStillValid(bookingTokenCache))return bookingTokenCache;if(!forceRefresh){const kvToken=await getTokenFromKV(env,"booking-api");if(kvToken){bookingTokenCache=kvToken;return kvToken}}const tokenData=await requestToken({tokenUrl:BOOKING_API_TOKEN_URL,clientId:env.GUESTY_CLIENT_ID,clientSecret:env.GUESTY_CLIENT_SECRET,scope:"booking_engine:api",label:"Guesty Booking API",missingMessage:"Missing Booking Engine credentials. Add GUESTY_CLIENT_ID and GUESTY_CLIENT_SECRET."});bookingTokenCache=tokenData;await putTokenToKV(env,"booking-api",tokenData);return tokenData}
async function requestToken({tokenUrl,clientId,clientSecret,scope,label,missingMessage}){assertRequired(clientId,missingMessage||"Missing client ID");assertRequired(clientSecret,missingMessage||"Missing client secret");const form=new URLSearchParams();form.set("grant_type","client_credentials");form.set("scope",scope);form.set("client_id",clientId);form.set("client_secret",clientSecret);const res=await fetch(tokenUrl,{method:"POST",headers:{accept:"application/json","content-type":"application/x-www-form-urlencoded"},body:form.toString()});const data=await parseGuestyResponse(res,label+" OAuth");return{token:data.access_token,expiresAt:Date.now()+Math.max(60,Number(data.expires_in||86400)-300)*1000,scope}}
function tokenStillValid(tokenData){return Boolean(tokenData?.token&&Number(tokenData.expiresAt||0)>Date.now()+TOKEN_CACHE_SAFETY_MS)}
