async function safeGuestyRoute(env,fn){try{return await fn()}catch(err){const status=err instanceof PublicError?err.status:500;const details=err instanceof PublicError?err.details:null;const body=details?.body||null;const isRateLimit=status===429||body?.error?.code==="TOO_MANY_REQUESTS"||body?.code==="TOO_MANY_REQUESTS";const isUnauthorized=status===401||body?.error?.code==="UNAUTHORIZED"||body?.code==="UNAUTHORIZED"||body?.error==="invalid_client";return json({ok:false,error:safeError(err),status,rateLimited:isRateLimit,unauthorized:isUnauthorized,message:isRateLimit?"Guesty is rate-limiting OAuth/API requests. Wait 10-20 minutes and test one route at a time.":isUnauthorized?"Guesty rejected these credentials. Check Open API and Booking Engine credentials separately.":safeError(err),details},status,env)}}
function errorResponse(err,env){const status=err instanceof PublicError?err.status:500;return json({ok:false,error:"Worker caught exception",message:safeError(err),details:err instanceof PublicError?err.details:undefined},status,env)}
function json(data,status=200,env={}){return corsResponse(JSON.stringify(data,null,2),status,env,{"content-type":"application/json; charset=utf-8"})}
function corsResponse(body,status=200,env={},extraHeaders={}){return new Response(body,{status,headers:{...corsHeaders(env||{}),...extraHeaders}})}
function corsHeaders(env={}){const defaults=["https://lschacht99.github.io","https://timbercrestmansions.com","https://www.timbercrestmansions.com"];const suffixes=[".squarespace.com"];const configured=String(env.ALLOWED_ORIGINS||"").split(",").map(x=>x.trim()).filter(Boolean);const allowAll=configured.includes("*");const allowList=new Set([...defaults,...configured.filter(o=>o!=="*")]);const requestOrigin=env.__REQUEST_ORIGIN||"";let originHost="";try{originHost=requestOrigin?new URL(requestOrigin).hostname:""}catch(_){}const originAllowed=allowList.has(requestOrigin)||suffixes.some(suffix=>originHost.endsWith(suffix));const headers={Vary:"Origin","Access-Control-Allow-Methods":"GET,POST,OPTIONS","Access-Control-Allow-Headers":"Content-Type, Accept, Authorization","Access-Control-Max-Age":"86400"};if(originAllowed&&requestOrigin)headers["Access-Control-Allow-Origin"]=requestOrigin;else if(allowAll)headers["Access-Control-Allow-Origin"]=requestOrigin||"*";return headers}
